import React from 'react';
import { Box, Container, Grid, Typography, Link, IconButton, Stack, Button } from '@mui/material';
import {
  LocalShipping, Security, HeadsetMic, SettingsBackupRestore,
  YouTube, Facebook, Chat, Apple, Google
} from '@mui/icons-material';

const TRUST_BADGES = [
  { icon: <LocalShipping sx={{ color: '#c62828' }} />, title: 'Giao h├áng miß╗àn ph├¡', desc: 'Cho ─æ╞ín h├áng tß╗½ 1.000.000─æ' },
  { icon: <Security sx={{ color: '#c62828' }} />, title: 'Ch├¡nh h├úng 100%', desc: 'Cam kß║┐t nguß╗ôn gß╗æc r├╡ r├áng' },
  { icon: <HeadsetMic sx={{ color: '#c62828' }} />, title: 'Hß╗ù trß╗ú 24/7', desc: 'Giß║úi ─æ├íp mß╗ìi thß║»c mß║»c' },
  { icon: <SettingsBackupRestore sx={{ color: '#c62828' }} />, title: '─Éß╗òi trß║ú 30 ng├áy', desc: 'Y├¬n t├óm khi mua sß║»m' },
];

const Footer = () => {
  const headerStyle = {
    color: '#c62828',
    fontWeight: 700,
    fontSize: '0.85rem',
    textTransform: 'uppercase',
    letterSpacing: '0.5px',
    mb: 2.5
  };

  const linkStyle = {
    color: '#666',
    fontSize: '0.85rem',
    textDecoration: 'none',
    display: 'block',
    mb: 1.2,
    '&:hover': { color: '#c62828', textDecoration: 'underline' }
  };

  const badgeStyle = {
    bgcolor: '#fff0f0',
    borderRadius: '8px',
    p: 1,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    width: 32,
    height: 32
  };

  return (
    <Box sx={{ mt: 'auto', borderTop: '1px solid #f0efef' }}>
      {/* ΓòÉΓòÉΓòÉΓòÉ TRUST BADGES (KEEPING OLD DESIGN BUT FITTING NEW COLOR) ΓòÉΓòÉΓòÉΓòÉ */}
      <Box sx={{ bgcolor: '#b71c1c', py: 4 }}>
        <Container maxWidth="lg" sx={{ px: { xs: 3, md: 2 } }}>
          <Box sx={{ 
            display: 'flex', 
            flexDirection: { xs: 'column', sm: 'row' }, 
            flexWrap: 'wrap', 
            gap: { xs: 3, md: 4 }, 
            justifyContent: 'center' 
          }}>
            {TRUST_BADGES.map((badge, idx) => (
              <Box key={idx} sx={{ 
                display: 'flex', 
                alignItems: 'center', 
                gap: 2.5, 
                color: 'white',
                width: { xs: '100%', sm: 'calc(50% - 16px)', md: 'calc(25% - 24px)' }
              }}>
                <Box sx={{ bgcolor: 'white', borderRadius: 2, p: 1.5, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  {badge.icon}
                </Box>
                <Box>
                  <Typography variant="body1" fontWeight={800}>{badge.title}</Typography>
                  <Typography variant="caption" sx={{ opacity: 0.9, fontSize: '0.8rem' }}>{badge.desc}</Typography>
                </Box>
              </Box>
            ))}
          </Box>
        </Container>
      </Box>

      {/* ΓòÉΓòÉΓòÉΓòÉ MAIN TIKI-STYLE FOOTER ΓòÉΓòÉΓòÉΓòÉ */}
      <Box sx={{ bgcolor: '#fffcfc', pt: 8, pb: 4 }}>
        <Container maxWidth="xl">
          <Grid container spacing={4} justifyContent="space-between">

            {/* Column 1: Customer Support */}
            <Grid item xs={12} sm={6} md={2.4}>
              <Typography sx={headerStyle}>Hß╗ù trß╗ú kh├ích h├áng</Typography>
              <Typography variant="h5" fontWeight={900} color="#1a1a1a" sx={{ mb: 0.5 }}></Typography>
              <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mb: 2.5 }}>

              </Typography>
              <Box>
                {['C├íc c├óu hß╗Åi th╞░ß╗¥ng gß║╖p', 'Gß╗¡i y├¬u cß║ºu hß╗ù trß╗ú', 'H╞░ß╗¢ng dß║½n ─æß║╖t h├áng', 'Ph╞░╞íng thß╗⌐c vß║¡n chuyß╗ân', 'Ch├¡nh s├ích ─æß╗òi trß║ú', 'Ch├¡nh s├ích bß║úo h├ánh'].map((txt, i) => (
                  <Link key={i} href="#" sx={linkStyle}>{txt}</Link>
                ))}
              </Box>
            </Grid>

            {/* Column 2: Digital Curator */}
            <Grid item xs={12} sm={6} md={2.4}>
              <Typography sx={headerStyle}>THE DIGITAL CURATOR</Typography>
              <Box>
                {['Vß╗ü GD Store', 'Ch├¡nh s├ích bß║úo mß║¡t', '─Éiß╗üu khoß║ún dß╗ïch vß╗Ñ'].map((txt, i) => (
                  <Link key={i} href="#" sx={linkStyle}>{txt}</Link>
                ))}
              </Box>
            </Grid>

            {/* Column 3: Partnerships */}
            <Grid item xs={12} sm={6} md={2.4}>
              <Typography sx={headerStyle}>Hß╗úp t├íc v├á li├¬n kß║┐t</Typography>
              <Box sx={{ mb: 4 }}>
                {['B├ín h├áng c├╣ng GD Store', 'D├ánh cho doanh nghiß╗çp', 'Ch╞░╞íng tr├¼nh ─æß╗æi t├íc'].map((txt, i) => (
                  <Link key={i} href="#" sx={linkStyle}>{txt}</Link>
                ))}
              </Box>

            </Grid>

            {/* Column 4: Payment Methods */}
            <Grid item xs={12} sm={6} md={2.4}>
              <Typography sx={headerStyle}>Ph╞░╞íng thß╗⌐c thanh to├ín</Typography>
              <Grid container spacing={1}>
                {['VISA', 'MOMO', 'ZALOPAY', 'ATM'].map((pay, i) => (
                  <Grid item xs={4} key={i}>
                    <Box sx={{
                      bgcolor: 'white', border: '1px solid #f0f0f0', borderRadius: '4px', p: 1,
                      textAlign: 'center', height: '100%', display: 'flex', alignItems: 'center',
                      justifyContent: 'center', boxShadow: '0 1px 3px rgba(0,0,0,0.02)'
                    }}>
                      <Typography variant="caption" fontWeight={800} color="#666" sx={{ fontSize: '0.65rem' }}>{pay}</Typography>
                    </Box>
                  </Grid>
                ))}
              </Grid>
            </Grid>

            {/* Column 5: Connect & Apps */}
            <Grid item xs={12} sm={6} md={2.4}>
              <Typography sx={headerStyle}>Kß║┐t nß╗æi vß╗¢i ch├║ng t├┤i</Typography>
              <Stack direction="row" spacing={1.5} sx={{ mb: 5 }}>
                {[<Security />, <Chat />].map((icon, i) => (
                  <IconButton key={i} size="small" sx={{
                    bgcolor: '#fff0f0', borderRadius: '8px',
                    '&:hover': { bgcolor: '#ffebeb' }, color: '#c62828'
                  }}>
                    {icon}
                  </IconButton>
                ))}
              </Stack>

              <Typography sx={headerStyle}>Tß║úi ß╗⌐ng dß╗Ñng tr├¬n ─æiß╗çn thoß║íi</Typography>
              <Stack direction="column" spacing={1.5}>
                <Button variant="contained" startIcon={<Apple />} sx={{
                  bgcolor: '#1a1a1a', textTransform: 'none', borderRadius: '6px',
                  fontSize: '0.8rem', justifyContent: 'flex-start', py: 0.8
                }}>
                  App Store
                </Button>
                <Button variant="contained" startIcon={<Google />} sx={{
                  bgcolor: '#1a1a1a', textTransform: 'none', borderRadius: '6px',
                  fontSize: '0.8rem', justifyContent: 'flex-start', py: 0.8
                }}>
                  Google Play
                </Button>
              </Stack>
            </Grid>

          </Grid>

          {/* Bottom section */}
          <Box sx={{ mt: 10, pt: 4, borderTop: '1px solid #f0efef', display: 'flex', flexDirection: { xs: 'column', md: 'row' }, justifyContent: 'space-between', alignItems: 'center', gap: 2 }}>
            <Box>
              <Typography variant="caption" color="text.secondary" display="block">
                Website th╞░╞íng mß║íi ─æiß╗çn tß╗¡ GD Store
              </Typography>
              <Typography variant="caption" color="text.secondary">
                ┬⌐ {new Date().getFullYear()} GD Store. Tß║Ñt cß║ú c├íc quyß╗ün ─æ╞░ß╗úc bß║úo l╞░u.
              </Typography>
            </Box>
            <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
              <Link href="#" variant="caption" color="text.secondary" underline="hover">Vß╗ü GD Store</Link>
              <Link href="#" variant="caption" color="text.secondary" underline="hover">Li├¬n hß╗ç</Link>
            </Box>
          </Box>
        </Container>
      </Box>
    </Box>
  );
};

export default Footer;

import React, { useState, useEffect } from 'react';
import {
  AppBar, Toolbar, Typography, IconButton,
  Badge, Menu, MenuItem, Box, Container, Avatar,
  InputBase, Button, Drawer, List, ListItem, ListItemText
} from '@mui/material';
import { ShoppingCart, Person, Search, Menu as MenuIcon } from '@mui/icons-material';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';

const NAV_LINKS = [
  { title: 'Nh├á bß║┐p', path: '/products?category=nha-bep' },
  { title: 'Ph├▓ng kh├ích', path: '/products?category=phong-khach' },
  { title: 'Ph├▓ng ngß╗º', path: '/products?category=phong-ngu' },
  { title: '─Éiß╗çn tß╗¡', path: '/products?category=dien-tu' },
  { title: 'Dß╗Ñng cß╗Ñ', path: '/products?category=dung-cu' },
  { title: 'Flash Sale', path: '/products?flashSale=true', special: true },
];

const Navbar = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, logout } = useAuth();
  const { cart } = useCart();
  const [anchorEl, setAnchorEl] = useState(null);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [scrolled, setScrolled] = useState(false);
  const [cartBounce, setCartBounce] = useState(false);

  // Shadow khi scroll
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Bounce cart khi sß╗æ l╞░ß╗úng thay ─æß╗òi
  const prevCartLen = React.useRef(cart?.length || 0);
  useEffect(() => {
    if (cart?.length > prevCartLen.current) {
      setCartBounce(true);
      setTimeout(() => setCartBounce(false), 600);
    }
    prevCartLen.current = cart?.length || 0;
  }, [cart?.length]);

  const handleMenu = (e) => setAnchorEl(e.currentTarget);
  const handleClose = () => setAnchorEl(null);
  const handleLogout = () => { logout(); handleClose(); navigate('/login'); };
  const handleDrawerToggle = () => setMobileOpen(!mobileOpen);

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      navigate(`/products?keyword=${encodeURIComponent(searchQuery.trim())}`);
      setSearchQuery('');
    }
  };

  const getAvatarText = () => {
    if (!user) return 'U';
    return user.name ? user.name.charAt(0).toUpperCase() : user.email.charAt(0).toUpperCase();
  };

  if (['/login', '/register'].includes(location.pathname)) return null;

  return (
    <AppBar
      position="sticky"
      elevation={scrolled ? 4 : 0}
      sx={{
        bgcolor: '#c62828',
        borderBottom: '1px solid #b71c1c',
        transition: 'box-shadow 0.3s ease, backdrop-filter 0.3s ease',
        boxShadow: scrolled ? '0 4px 24px rgba(198,40,40,0.4)' : 'none',
      }}
    >
      <Container maxWidth="lg" sx={{ px: { xs: 1, sm: 2, md: 3 } }}>
        <Toolbar sx={{ px: '0 !important', minHeight: '80px', justifyContent: 'space-between', flexWrap: 'nowrap' }}>

          {/* ΓöÇΓöÇ MOBILE MENU BUTTON ΓöÇΓöÇ */}
          <Box sx={{ display: { xs: 'flex', md: 'none' }, alignItems: 'center' }}>
            <IconButton onClick={handleDrawerToggle} sx={{ color: 'white', ml: -1, mr: 1 }}>
              <MenuIcon />
            </IconButton>
          </Box>

          {/* ΓöÇΓöÇ LOGO ΓöÇΓöÇ */}
          <Box
            component={Link} to="/"
            sx={{
              display: 'flex', alignItems: 'baseline', gap: 0.5,
              textDecoration: 'none', mr: { xs: 2, md: 4 },
              transition: 'transform 0.25s ease',
              '&:hover': { transform: 'scale(1.04)' }
            }}
          >
            <Typography variant="h3" sx={{
              fontWeight: 900, fontStyle: 'italic', color: 'white',
              letterSpacing: '-2px', fontSize: { xs: '2rem', md: '2.5rem' },
              textShadow: '2px 2px 4px rgba(0,0,0,0.25)'
            }}>GD</Typography>
            <Typography variant="h5" sx={{
              fontWeight: 600, fontStyle: 'italic', color: 'white',
              letterSpacing: '-0.5px', fontSize: { xs: '1.2rem', md: '1.5rem' }, opacity: 0.9
            }}>STORE</Typography>
          </Box>

          {/* ΓöÇΓöÇ NAV LINKS ΓöÇΓöÇ */}
          <Box sx={{ display: { xs: 'none', md: 'flex' }, gap: { md: 2, lg: 4 }, flexGrow: 1, justifyContent: 'center', overflow: 'hidden' }}>
            {NAV_LINKS.map((link, i) => (
              <Box
                key={link.title}
                component={Link} to={link.path}
                sx={{
                  color: link.special ? '#ffeb3b' : 'white',
                  textDecoration: 'none',
                  fontSize: '0.9rem',
                  fontWeight: 600,
                  position: 'relative',
                  pb: 0.5,
                  animation: 'slideDown 0.4s ease both',
                  animationDelay: `${i * 0.06}s`,
                  transition: 'color 0.2s, transform 0.2s',
                  '&::after': {
                    content: '""',
                    position: 'absolute',
                    bottom: 0, left: 0,
                    width: '0%', height: '2px',
                    bgcolor: link.special ? '#ffeb3b' : 'rgba(255,255,255,0.9)',
                    transition: 'width 0.3s ease',
                    borderRadius: '2px',
                  },
                  '&:hover': {
                    color: link.special ? '#fff176' : 'rgba(255,255,255,0.95)',
                    transform: 'translateY(-2px)',
                  },
                  '&:hover::after': { width: '100%' },
                }}
              >
                {link.special ? 'ΓÜí Flash Sale' : link.title}
              </Box>
            ))}
          </Box>

          {/* ΓöÇΓöÇ ICONS PHß║óI ΓöÇΓöÇ */}
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>

            {/* Search */}
            <Box sx={{ display: { xs: 'none', sm: 'flex' }, alignItems: 'center', position: 'relative' }}>
              <form onSubmit={handleSearch} style={{ display: 'flex' }}>
                <InputBase
                  placeholder="T├¼m kiß║┐m sß║ún phß║⌐m..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  sx={{
                    bgcolor: 'rgba(255,255,255,0.18)',
                    px: 2, py: 0.5, borderRadius: 2,
                    width: 200, fontSize: '0.85rem', color: 'white', pr: 4,
                    transition: 'background 0.3s, width 0.3s',
                    '&:focus-within': {
                      bgcolor: 'rgba(255,255,255,0.28)',
                      width: 240,
                    },
                    '& input::placeholder': { color: 'rgba(255,255,255,0.7)', opacity: 1 }
                  }}
                />
                <IconButton type="submit" size="small"
                  sx={{ position: 'absolute', right: 4, top: '50%', transform: 'translateY(-50%)', color: 'white' }}>
                  <Search sx={{ fontSize: 20 }} />
                </IconButton>
              </form>
            </Box>

            {/* Cart vß╗¢i bounce */}
            <IconButton
              component={Link} to="/cart"
              sx={{
                color: 'white',
                transition: 'transform 0.2s',
                animation: cartBounce ? 'bounceCart 0.5s ease' : 'none',
                '&:hover': { transform: 'scale(1.15)' }
              }}
            >
              <Badge
                badgeContent={cart?.length || 0}
                sx={{ '& .MuiBadge-badge': { bgcolor: 'white', color: '#c62828', fontWeight: 'bold' } }}
              >
                <ShoppingCart />
              </Badge>
            </IconButton>

            {/* User menu */}
            {user ? (
              <>
                <IconButton onClick={handleMenu} sx={{ p: 0.5, transition: 'transform 0.2s', '&:hover': { transform: 'scale(1.1)' } }}>
                  <Avatar
                    src={user?.avatarUrl}
                    sx={{
                      width: 32, height: 32,
                      bgcolor: 'rgba(255,255,255,0.2)',
                      color: 'white', fontSize: '0.9rem', fontWeight: 'bold',
                      border: '2px solid rgba(255,255,255,0.4)',
                      transition: 'border-color 0.2s',
                      '&:hover': { borderColor: 'white' }
                    }}>
                    {getAvatarText()}
                  </Avatar>
                </IconButton>
                <Menu
                  anchorEl={anchorEl}
                  open={Boolean(anchorEl)}
                  onClose={handleClose}
                  PaperProps={{
                    elevation: 3,
                    sx: {
                      mt: 1.5, borderRadius: 2, minWidth: 160,
                      animation: 'scaleIn 0.2s cubic-bezier(0.34,1.56,0.64,1)',
                      transformOrigin: 'top right',
                      overflow: 'visible',
                      '&::before': {
                        content: '""',
                        display: 'block',
                        position: 'absolute',
                        top: -6, right: 14,
                        width: 12, height: 12,
                        bgcolor: 'background.paper',
                        transform: 'rotate(45deg)',
                        zIndex: 0,
                        boxShadow: '-1px -1px 3px rgba(0,0,0,0.08)',
                      }
                    }
                  }}
                  transformOrigin={{ horizontal: 'right', vertical: 'top' }}
                  anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
                >
                  <MenuItem onClick={() => { handleClose(); navigate('/profile'); }} sx={{ fontSize: '0.95rem', '&:hover': { bgcolor: '#fff5f5', color: '#c62828' } }}>
                    <Person sx={{ mr: 1.5, fontSize: 20, color: '#555' }} /> Hß╗ô s╞í
                  </MenuItem>
                  {user.role === 'admin' && (
                    <MenuItem onClick={() => { handleClose(); navigate('/admin'); }} sx={{ fontSize: '0.95rem', '&:hover': { bgcolor: '#fff5f5', color: '#c62828' } }}>
                      ≡ƒææ Quß║ún trß╗ï vi├¬n
                    </MenuItem>
                  )}
                  {(user.role === 'shipper' || user.role === 'admin') && (
                    <MenuItem onClick={() => { handleClose(); navigate('/shipper'); }} sx={{ fontSize: '0.95rem', '&:hover': { bgcolor: '#f3f0ff', color: '#7c3aed' } }}>
                      ≡ƒÜÜ Trang Shipper
                    </MenuItem>
                  )}
                  <MenuItem onClick={handleLogout} sx={{ fontSize: '0.95rem', color: '#c62828', '&:hover': { bgcolor: '#fff5f5' } }}>
                    ≡ƒÜ¬ ─É─âng xuß║Ñt
                  </MenuItem>
                </Menu>
              </>
            ) : (
              <IconButton
                component={Link} to="/login"
                sx={{ color: 'white', transition: 'transform 0.2s', '&:hover': { transform: 'scale(1.15)' } }}
              >
                <Person />
              </IconButton>
            )}
          </Box>
        </Toolbar>
      </Container>

      {/* ΓöÇΓöÇ MOBILE DRAWER ΓöÇΓöÇ */}
      <Drawer
        anchor="left"
        open={mobileOpen}
        onClose={handleDrawerToggle}
        sx={{
          display: { xs: 'block', md: 'none' },
          '& .MuiDrawer-paper': { boxSizing: 'border-box', width: 260, bgcolor: '#fafafa' },
        }}
      >
        <Box sx={{ p: 2, bgcolor: '#c62828', color: 'white', display: 'flex', alignItems: 'center', gap: 1 }}>
          <Typography variant="h5" sx={{ fontWeight: 900, fontStyle: 'italic', letterSpacing: '-1px' }}>GD STORE</Typography>
        </Box>
        <Box sx={{ p: 2 }}>
          {/* Mobile Search */}
          <form onSubmit={(e) => { handleSearch(e); handleDrawerToggle(); }}>
            <InputBase
              placeholder="T├¼m kiß║┐m sß║ún phß║⌐m..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              sx={{
                bgcolor: '#eee',
                px: 2, py: 0.5, borderRadius: 2,
                width: '100%', fontSize: '0.85rem', mb: 2
              }}
              endAdornment={<Search sx={{ color: '#aaa', fontSize: 20 }} />}
            />
          </form>
          <List disablePadding>
            {NAV_LINKS.map((link) => (
              <ListItem
                button
                key={link.title}
                component={Link}
                to={link.path}
                onClick={handleDrawerToggle}
                sx={{ borderRadius: 1, mb: 0.5, '&:hover': { bgcolor: 'rgba(0,0,0,0.04)' } }}
              >
                <ListItemText
                  primary={link.special ? 'ΓÜí Flash Sale' : link.title}
                  primaryTypographyProps={{ fontWeight: 600, color: link.special ? '#ee4d2d' : '#333' }}
                />
              </ListItem>
            ))}
            {(user?.role === 'admin' || user?.role === 'shipper') && (
              <ListItem button component={Link} to="/shipper" onClick={handleDrawerToggle}
                sx={{ borderRadius: 1, mb: 0.5, '&:hover': { bgcolor: '#f3f0ff' } }}>
                <ListItemText primary="≡ƒÜÜ Trang Shipper"
                  primaryTypographyProps={{ fontWeight: 700, color: '#7c3aed' }} />
              </ListItem>
            )}
          </List>
        </Box>
      </Drawer>
    </AppBar>
  );
};

export default Navbar;

import React from 'react';
import { 
  Card, CardMedia, CardContent, CardActions, 
  Typography, Button, Box, Rating, Chip, IconButton
} from '@mui/material';
import { Favorite, FavoriteBorder, ShoppingCart, LocalShipping } from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { useState } from 'react';
import { getFirstImage } from '../utils/imageUtils';

const ProductCard = ({ product }) => {
  const navigate = useNavigate();
  const { addToCart } = useCart();
  const { user } = useAuth();
  const [isFav, setIsFav] = useState(false);

  const formatPrice = (price) => {
    return new Intl.NumberFormat('vi-VN', {
      style: 'currency',
      currency: 'VND'
    }).format(price).replace('Γé½', '─æ');
  };

  const handleAddToCart = async () => {
    if (!user) {
      navigate('/login');
      return;
    }
    const result = await addToCart(product.id, 1);
    if (result.success) {
      alert('─É├ú th├¬m v├áo giß╗Å h├áng!');
    }
  };

  return (
    <Card sx={{
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      position: 'relative',
      borderRadius: 2,
      border: 'none',
      boxShadow: '0 1px 4px rgba(0,0,0,0.08)',
      transition: 'all 0.25s ease',
      cursor: 'pointer',
      '&:hover': {
        transform: 'translateY(-6px)',
