        const revenue = inDay.reduce((sum, o) => sum + (Number(o.totalAmount) || 0), 0);
        return {
          label: `${dayNames[d.getDay()]} (${d.getDate()}/${d.getMonth() + 1})`,
          revenue,
          orders: inDay.length
