    const maxPrice = params.get('maxPrice') || '';
    const flashSale = params.get('flashSale') === 'true';
    setFilters(prev => ({ ...prev, category, keyword, minPrice, maxPrice, flashSale }));
    setTempFilters({ keyword, category, minPrice, maxPrice });
  }, [location.search]);


  // Fetch products when filters change
  useEffect(() => {
    fetchProducts();
  }, [page, filters]);

  const fetchProducts = async () => {
    try {
      setLoading(true);

      // Build query params
      const params = new URLSearchParams();
      params.append('page', page);
      params.append('limit', 20);

      if (filters.keyword) params.append('keyword', filters.keyword);
      if (filters.category) params.append('category', filters.category);

      let finalMinPrice = filters.minPrice;
      let finalMaxPrice = filters.maxPrice;

      if (finalMinPrice === 'over_3000000') {
        finalMinPrice = '3000000';
      }

      if (finalMaxPrice === 'over_3000000') {
        if (!finalMinPrice) {
          finalMinPrice = '3000000';
        }
        finalMaxPrice = '';
      }

      if (finalMinPrice) params.append('minPrice', finalMinPrice);
      if (finalMaxPrice) params.append('maxPrice', finalMaxPrice);

      if (filters.sortBy) params.append('sortBy', filters.sortBy);
      if (filters.flashSale) params.append('flashSale', 'true');
      // Debug: Xem API ─æang gß╗ìi g├¼
      console.log('≡ƒöì Fetching with flashSale:', filters.flashSale);
      console.log('≡ƒöì Fetching products with filters:', Object.fromEntries(params));

      const { data } = await API.get(`/products?${params}`);

      console.log('Γ£à Received products:', data.products?.length || 0);

      setProducts(data.products || []);
      setPages(data.pages || 1);
      setTotalProducts(data.total || 0);
      setError('');
    } catch (error) {
      console.error('Lß╗ùi tß║úi sß║ún phß║⌐m:', error);
      setError('Kh├┤ng thß╗â tß║úi sß║ún phß║⌐m. Vui l├▓ng thß╗¡ lß║íi sau.');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = () => {
    setFilters({
      ...filters,
      keyword: tempFilters.keyword,
