    processing:         { label: '─Éang xß╗¡ l├╜',       color: '#2196f3', bg: '#e3f2fd' },
    shipped:            { label: 'Chß╗¥ shipper nhß║¡n', color: '#6366f1', bg: '#eef2ff' },
    out_for_delivery:   { label: '─Éang giao',         color: '#7c3aed', bg: '#f3f0ff' },
